# ---- In-memory storage ----

# Images: {image_id: {"filename": str, "data": bytes, "uploaded_at": str}}
image_store: dict = {}

# Annotations: {image_id: {annotator_id: {"label": str, "timestamp": str, "confidence": float}}}
annotation_store: dict = {}

