# Configuration
MIN_ANNOTATIONS_FOR_AGGREGATION = int(os.environ.get("MIN_ANNOTATIONS", "3"))
MAJORITY_THRESHOLD = float(os.environ.get("MAJORITY_THRESHOLD", "0.5"))


# ---- Pydantic Models ----

class AnnotatorRegistration(BaseModel):
    name: str
