# ---- Helper Functions ----

def extract_features(image_data: bytes) -> np.ndarray:
    """Extract simple features from image data for model training."""
    if PIL_AVAILABLE:
        try:
            img = Image.open(io.BytesIO(image_data))
            img = img.convert("RGB")
            img = img.resize((32, 32))
            arr = np.array(img).flatten().astype(np.float32) / 255.0
            return arr
        except Exception:
            pass
    # Fallback: use raw bytes as features (hash-based)
    raw = np.frombuffer(image_data[:1024].ljust(1024, b'\x00'), dtype=np.uint8)
    return raw.astype(np.float32) / 255.0


def aggregate_labels_for_image(image_id: str) -> Optional[dict]:
    """Aggregate labels for a single image using majority voting."""
    if image_id not in annotation_store:
        return None

    annotations = annotation_store[image_id]
    if len(annotations) < MIN_ANNOTATIONS_FOR_AGGREGATION:
        return None

    # Weighted majority voting based on confidence
    label_weights: dict = {}
    label_counts: dict = {}
    for annotator_id, ann in annotations.items():
        label = ann["label"]
        confidence = ann.get("confidence", 1.0)
        label_weights[label] = label_weights.get(label, 0.0) + confidence
        label_counts[label] = label_counts.get(label, 0) + 1

    # Find the label with highest weighted votes
    best_label = max(label_weights, key=label_weights.get)
    total_votes = len(annotations)
    vote_count = label_counts[best_label]
    agreement_ratio = vote_count / total_votes

    result = {
        "label": best_label,
        "vote_count": vote_count,
        "total_votes": total_votes,
        "agreement_ratio": agreement_ratio,
        "all_votes": dict(label_counts)
    }

    # Only accept if above threshold
    if agreement_ratio >= MAJORITY_THRESHOLD:
        aggregated_labels[image_id] = result

    return result


def aggregate_all_labels():
    """Re-aggregate labels for all images."""
    for image_id in annotation_store:
        aggregate_labels_for_image(image_id)


