@app.post("/annotators/register", response_model=AnnotatorResponse)
def register_annotator(registration: AnnotatorRegistration):
    """Register a new annotator."""
    annotator_id = registration.annotator_id or str(uuid.uuid4())

    if annotator_id in annotator_store:
        raise HTTPException(status_code=409, detail=f"Annotator {annotator_id} already exists")

    annotator = {
        "name": registration.name,
        "registered_at": datetime.utcnow().isoformat(),
        "annotation_count": 0
    }
    annotator_store[annotator_id] = annotator

    return AnnotatorResponse(annotator_id=annotator_id, **annotator)


@app.get("/annotators", response_model=list[AnnotatorResponse])
def list_annotators():
    """List all registered annotators."""
    return [
        AnnotatorResponse(annotator_id=aid, **adata)
        for aid, adata in annotator_store.items()
    ]


@app.get("/annotators/{annotator_id}", response_model=AnnotatorResponse)
def get_annotator(annotator_id: str):
    """Get annotator details."""
    if annotator_id not in annotator_store:
        raise HTTPException(status_code=404, detail="Annotator not found")
    return AnnotatorResponse(annotator_id=annotator_id, **annotator_store[annotator_id])


