# --- Annotation Submission ---

@app.post("/annotations", response_model=AnnotationResponse)
def submit_annotation(submission: AnnotationSubmission):
    """Submit a label annotation for an image."""
    if submission.image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found")

    if submission.annotator_id not in annotator_store:
        raise HTTPException(status_code=404, detail="Annotator not found. Please register first.")

    if submission.image_id not in annotation_store:
        annotation_store[submission.image_id] = {}

    # Check if annotator already labeled this image
    if submission.annotator_id in annotation_store[submission.image_id]:
        raise HTTPException(
            status_code=409,
            detail="Annotator has already labeled this image. Use PUT to update."
        )

    timestamp = datetime.utcnow().isoformat()
    annotation = {
        "label": submission.label,
        "confidence": submission.confidence,
        "timestamp": timestamp
    }
    annotation_store[submission.image_id][submission.annotator_id] = annotation
    annotator_store[submission.annotator_id]["annotation_count"] += 1

    # Try to aggregate after each new annotation
    aggregate_labels_for_image(submission.image_id)

    return AnnotationResponse(
        image_id=submission.image_id,
        annotator_id=submission.annotator_id,
        label=submission.label,
        confidence=submission.confidence,
        timestamp=timestamp
    )


@app.put("/annotations", response_model=AnnotationResponse)
def update_annotation(submission: AnnotationSubmission):
    """Update an existing annotation."""
    if submission.image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found")

    if submission.annotator_id not in annotator_store:
        raise HTTPException(status_code=404, detail="Annotator not found")

    if (submission.image_id not in annotation_store or
            submission.annotator_id not in annotation_store[submission.image_id]):
        raise HTTPException(status_code=404, detail="No existing annotation to update")

    timestamp = datetime.utcnow().isoformat()
    annotation_store[submission.image_id][submission.annotator_id] = {
        "label": submission.label,
        "confidence": submission.confidence,
        "timestamp": timestamp
    }

    # Re-aggregate
    aggregate_labels_for_image(submission.image_id)

    return AnnotationResponse(
        image_id=submission.image_id,
        annotator_id=submission.annotator_id,
        label=submission.label,
        confidence=submission.confidence,
        timestamp=timestamp
    )


@app.post("/annotations/bulk")
def submit_bulk_annotations(bulk: BulkAnnotationSubmission):
    """Submit multiple annotations at once."""
    results = []
    errors = []

    for submission in bulk.annotations:
        try:
            if submission.image_id not in image_store:
                errors.append({"submission": submission.dict(), "error": "Image not found"})
                continue
            if submission.annotator_id not in annotator_store:
                errors.append({"submission": submission.dict(), "error": "Annotator not found"})
                continue
            if submission.image_id not in annotation_store:
                annotation_store[submission.image_id] = {}
            if submission.annotator_id in annotation_store[submission.image_id]:
                errors.append({"submission": submission.dict(), "error": "Already annotated"})
                continue

            timestamp = datetime.utcnow().isoformat()
            annotation_store[submission.image_id][submission.annotator_id] = {
                "label": submission.label,
                "confidence": submission.confidence,
                "timestamp": timestamp
            }
            annotator_store[submission.annotator_id]["annotation_count"] += 1
            aggregate_labels_for_image(submission.image_id)

            results.append({
                "image_id": submission.image_id,
                "annotator_id": submission.annotator_id,
                "label": submission.label,
                "status": "success"
            })
        except Exception as e:
            errors.append({"submission": submission.dict(), "error": str(e)})

    return {
        "successful": len(results),
        "failed": len(errors),
        "results": results,
        "errors": errors
    }


