# --- Model Training ---

@app.post("/model/train", response_model=TrainResponse)
def train_model(request: TrainRequest = TrainRequest()):
    """Train a model on the aggregated labeled data without validation."""
    # Collect training data
    X = []
    y = []

    for image_id, label_data in aggregated_labels.items():
        # Filter by agreement ratio if specified
        if label_data["agreement_ratio"] < request.min_agreement_ratio:
            continue

        if image_id not in image_store:
            continue

        features = extract_features(image_store[image_id]["data"])
        X.append(features)
        y.append(label_data["label"])

    if len(X) == 0:
        raise HTTPException(
            status_code=400,
            detail="No labeled data available for training. Need aggregated labels first."
        )

    if len(set(y)) < 2:
        raise HTTPException(
            status_code=400,
            detail=f"Need at least 2 classes for training. Currently have: {list(set(y))}"
        )

    X = np.array(X)
    label_encoder = LabelEncoder()
    y_encoded = label_encoder.fit_transform(y)

    # Train model without validation
    model = LogisticRegression(
        max_iter=1000,
        multi_class='multinomial',
        solver='lbfgs',
        C=1.0
    )
    model.fit(X, y_encoded)

    # Calculate training accuracy (no validation set)
    train_predictions = model.predict(X)
    train_accuracy = float(np.mean(train_predictions == y_encoded))

    # Store model
    trained_at = datetime.utcnow().isoformat()
    model_store["model"] = model
    model_store["label_encoder"] = label_encoder
    model_store["trained_at"] = trained_at
    model_store["num_samples"] = len(X)
    model_store["classes"] = list(label_encoder.classes_)
    model_store["accuracy_on_train"] = train_accuracy

    return TrainResponse(
        status="trained_successfully",
        num_samples=len(X),
        classes=list(label_encoder.classes_),
        accuracy_on_train=train_accuracy,
        trained_at=trained_at
    )


@app.post("/model/predict/{image_id}", response_model=PredictionResponse)
def predict_image(image_id: str):
    """Predict the label for an image using the trained model."""
    if model_store["model"] is None:
        raise HTTPException(status_code=400, detail="No model trained yet. Train a model first.")

    if image_id not in image_store:
        raise HTTPException(status_code=404, detail="Image not found")

    features = extract_features(image_store[image_id]["data"])
    features = features.reshape(1, -1)

    model = model_store["model"]
    label_encoder = model_store["label_encoder"]

    prediction = model.predict(features)[0]
    probabilities = model.predict_proba(features)[0]

    predicted_label = label_encoder.inverse_transform([prediction])[0]
    confidence = {
        label_encoder.classes_[i]: float(prob)
        for i, prob in enumerate(probabilities)
    }

    return PredictionResponse(
        image_id=image_id,
        predicted_label=predicted_label,
        confidence=confidence
    )


@app.post("/model/predict_upload")
async def predict_uploaded_image(file: UploadFile = File(...)):
    """Predict the label for an uploaded image without storing it."""
    if model_store["model"] is None:
        raise HTTPException(status_code=400, detail="No model trained yet.")

    data = await file.read()
    features = extract_features(data)
    features = features.reshape(1, -1)

    model = model_store["model"]
    label_encoder = model_store["label_encoder"]

    prediction = model.predict(features)[0]
    probabilities = model.predict_proba(features)[0]

    predicted_label = label_encoder.inverse_transform([prediction])[0]
    confidence = {
        label_encoder.classes_[i]: float(prob)
        for i, prob in enumerate(probabilities)
    }

    return {
        "filename": file.filename,
        "predicted_label": predicted_label,
        "confidence": confidence
    }


