@app.get("/stats")
def get_statistics():
    """Get overall system statistics."""
    total_images = len(image_store)
    total_annotators = len(annotator_store)
    total_annotations = sum(len(anns) for anns in annotation_store.values())
    total_aggregated = len(aggregated_labels)

    # Annotator stats
    annotator_stats = []
    for aid, adata in annotator_store.items():
        annotator_stats.append({
            "annotator_id": aid,
            "name": adata["name"],
            "annotation_count": adata["annotation_count"]
        })

    # Label distribution
    label_distribution = Counter()
    for label_data in aggregated_labels.values():
        label_distribution[label_data["label"]] += 1

    # Agreement statistics
    agreement_ratios = [data["agreement_ratio"] for data in aggregated_labels.values()]
    avg_agreement = float(np.mean(agreement_ratios)) if agreement_ratios else 0.0

    return {
        "total_images": total_images,
        "total_annotators": total_annotators,
        "total_annotations": total_annotations,
        "total_aggregated_labels": total_aggregated,
        "images_needing_annotations": total_images - total_aggregated,
        "min_annotations_required": MIN_ANNOTATIONS_FOR_AGGREGATION,
        "majority_threshold": MAJORITY_THRESHOLD,
        "average_agreement_ratio": avg_agreement,
        "label_distribution": dict(label_distribution),
        "annotator_stats": sorted(annotator_stats, key=lambda x: x["annotation_count"], reverse=True),
        "model_trained": model_store["model"] is not None,
        "model_info": {
            "trained_at": model_store["trained_at"],
            "num_samples": model_store["num_samples"],
            "classes": model_store["classes"],
            "accuracy_on_train": model_store["accuracy_on_train"]
        } if model_store["model"] is not None else None
    }


@app.get("/stats/annotator/{annotator_id}")
def get_annotator_stats(annotator_id: str):
    """Get detailed statistics for a specific annotator."""
    if annotator_id not in annotator_store:
        raise HTTPException(status_code=404, detail="Annotator not found")

    # Find all annotations by this annotator
    annotations = []
    agreements = 0
    total_with_aggregation = 0

    for image_id, anns in annotation_store.items():
        if annotator_id in anns:
            ann = anns[annotator_id]
            agreed = None
            if image_id in aggregated_labels:
                total_with_aggregation += 1
                agreed = ann["label"] == aggregated_labels[image_id]["label"]
                if agreed:
                    agreements += 1

            annotations.append({
                "image_id": image_id,
                "label": ann["label"],
                "confidence": ann["confidence"],
                "timestamp": ann["timestamp"],
                "agreed_with_majority": agreed
            })

    agreement_rate = agreements / total_with_aggregation if total_with_aggregation > 0 else None

    return {
        "annotator_id": annotator_id,
        "name": annotator_store[annotator_id]["name"],
        "total_annotations": len(annotations),
        "agreement_rate": agreement_rate,
        "annotations": annotations
    }


# --- Inter-Annotator Agreement ---

@app.get("/stats/agreement")
def get_inter_annotator_agreement():
    """Calculate inter-annotator agreement metrics."""
    # Pairwise agreement
    annotator_ids = list(annotator_store.keys())
    pairwise_agreements = {}

    for i, a1 in enumerate(annotator_ids):
        for j, a2 in enumerate(annotator_ids):
            if i >= j:
                continue
            agree = 0
            total = 0
            for image_id, anns in annotation_store.items():
                if a1 in anns and a2 in anns:
                    total += 1
                    if anns[a1]["label"] == anns[a2]["label"]:
                        agree += 1
            if total > 0:
                pairwise_agreements[f"{a1}_vs_{a2}"] = {
                    "agreement_rate": agree / total,
                    "agreed": agree,
                    "total_shared": total
                }

    # Overall Fleiss-like agreement (simple version)
    total_agreement = 0
    total_pairs = 0
    for img_id, anns in annotation_store.items():
        labels = [a["label"] for a in anns.values()]
        n = len(labels)
        if n < 2:
            continue
        label_counts = Counter(labels)
        # Number of agreeing pairs
        pairs = sum(c * (c - 1) for c in label_counts.values())
        total_possible = n * (n - 1)
        total_agreement += pairs
        total_pairs += total_possible

    overall_agreement = total_agreement / total_pairs if total_pairs > 0 else None

    return {
        "overall_agreement": overall_agreement,
        "pairwise_agreements": pairwise_agreements,
        "num_annotators": len(annotator_ids)
    }


